3	import (
4		"fmt"
5		"go/ast"
6		"go/parser"
7		"go/token"
8		"os"
9		"path/filepath"
10		"strings"
11		"testing"
12	)
13	
14	// TestNoLiveHarnessExecInDefaultSuite is the AC #5 static guard for the
15	// "Remove live harness execution tests from DDx" cleanup.
16	//
17	// Harness execution now lives in Fizeau. The default DDx test suite
18	// (`go test ./...`) must not exec real third-party harness binaries
19	// (opencode, claude, codex, gemini, pi). The single allowed file that
20	// references those binaries from a test is
21	// internal/agent/live_harness_integration_test.go, which is gated by
22	// `//go:build live_harness`.
23	//
24	// This test walks every *_test.go file in the cli/ tree and fails if any
25	// untagged file passes one of those binary names as a string literal to
26	// exec.Command, exec.CommandContext, exec.LookPath, or DefaultLookPath.
27	func TestNoLiveHarnessExecInDefaultSuite(t *testing.T) {
28		cliRoot := findCLIRoot(t)
29		harnessNames := map[string]struct{}{
30			"opencode": {},
31			"claude":   {},
32			"codex":    {},
33			"gemini":   {},
34			"pi":       {},
35		}
36		gatedCallees := map[string]struct{}{
37			"Command":         {},
38			"CommandContext":  {},
39			"LookPath":        {},
40			"DefaultLookPath": {},
41		}
42	
43		allowed := filepath.Join("internal", "agent", "live_harness_integration_test.go")
44	
45		var offenders []string
46		err := filepath.Walk(cliRoot, func(path string, info os.FileInfo, err error) error {
47			if err != nil {
48				return err
49			}
50			if info.IsDir() {
51				base := filepath.Base(path)
52				if base == "vendor" || base == "node_modules" || base == "build" || base == "dist" {
53					return filepath.SkipDir
54				}
55				return nil
56			}
57			if !strings.HasSuffix(path, "_test.go") {
58				return nil
59			}
60			rel, _ := filepath.Rel(cliRoot, path)
61			if rel == allowed {
62				return nil
63			}
64	
65			fset := token.NewFileSet()
66			f, perr := parser.ParseFile(fset, path, nil, parser.ParseComments)
67			if perr != nil {
68				return nil
69			}
70			// Skip files already gated behind a build tag that disables them by
71			// default (any //go:build line containing live_harness).
72			if hasLiveHarnessBuildTag(f) {
73				return nil
74			}
75	
76			ast.Inspect(f, func(n ast.Node) bool {
77				call, ok := n.(*ast.CallExpr)
78				if !ok {
79					return true
80				}
81				callee := ""
82				switch fn := call.Fun.(type) {
83				case *ast.SelectorExpr:
84					callee = fn.Sel.Name
85				case *ast.Ident:
86					callee = fn.Name
87				}
88				if _, ok := gatedCallees[callee]; !ok {
89					return true
90				}
91				if len(call.Args) == 0 {
92					return true
93				}
94				lit, ok := call.Args[0].(*ast.BasicLit)
95				if !ok || lit.Kind != token.STRING {
96					return true
97				}
98				val := strings.Trim(lit.Value, "`\"")
99				if _, bad := harnessNames[val]; bad {
100					pos := fset.Position(call.Pos())
101					offenders = append(offenders,
102						fmt.Sprintf("%s:%d %s(%q)", rel, pos.Line, callee, val))
103				}
104				return true
105			})
106			return nil
107		})
108		if err != nil {
109			t.Fatalf("walk failed: %v", err)
110		}
111	
112		if len(offenders) > 0 {
113			t.Fatalf("default test suite exec's real harness binaries; gate behind //go:build live_harness or move to Fizeau:\n  %s",
114				strings.Join(offenders, "\n  "))
115		}
116	}
117	
118	func hasLiveHarnessBuildTag(f *ast.File) bool {
119		for _, cg := range f.Comments {
120			for _, c := range cg.List {
121				if strings.HasPrefix(c.Text, "//go:build") && strings.Contains(c.Text, "live_harness") {
122					return true
123				}
124				if strings.HasPrefix(c.Text, "// +build") && strings.Contains(c.Text, "live_harness") {
125					return true
126				}
127			}
128		}
129		return false
130	}
131	
132	func findCLIRoot(t *testing.T) string {
133		t.Helper()
134		wd, err := os.Getwd()
135		if err != nil {
136			t.Fatalf("getwd: %v", err)
137		}
138		dir := wd
139		for i := 0; i < 8; i++ {
140			if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
141				return dir
142			}
143			dir = filepath.Dir(dir)
144		}
145		t.Fatalf("could not locate cli/ root from %s", wd)
146		return ""
147	}
